import { DB } from './db.js';
import { CALC, fmt, fmtNum, today, numberToWords, categorizeSummaryItem } from './calc.js';
import { state } from '../main.js';

const LOGO_BASE64 = "";
function base64ToArrayBuffer(base64) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes.buffer;
}
let logoArrayBuffer = base64ToArrayBuffer(LOGO_BASE64);

// =============================================


function applyPageSetup(ws, repeatRowsCount) {

  // Khổ giấy A4 ngang

  ws['!pageSetup'] = {

    paperSize:     9,           // 9 = A4

    orientation:   'landscape',

    fitToPage:     true,

    fitToWidth:    1,           // vừa 1 trang ngang (tự thu nhỏ nếu cần)

    fitToHeight:   0,           // tự do theo chiều dọc

    autoBreaks:    true,

    horizontalDpi: 300,

    verticalDpi:   300,

  };

  // Lề trang (đơn vị: inches)

  ws['!margins'] = {

    left:   0.3,

    right:  0.3,

    top:    0.4,

    bottom: 0.5,

    header: 0.2,

    footer: 0.2,

  };

  // Footer: góc trái = ngày giờ in | góc phải = Trang P/N

  ws['!headerFooter'] = {

    oddFooter:  '&L&"Arial,Italic"Du-Toan-BlueAI Lab&R&"Arial,Bold"Trang &P/&N',

    evenFooter: '&L&"Arial,Italic"Du-Toan-BlueAI Lab&R&"Arial,Bold"Trang &P/&N',

  };

  // Rows to repeat at top khi in: lặp lại từ dòng 0 đến repeatRowsCount-1 (0-indexed)

  const rpt = (repeatRowsCount && repeatRowsCount > 0) ? repeatRowsCount : 9;

  ws['!printHeader'] = { rows: { min: 0, max: rpt - 1 } };

}

function applyBorders(ws, headerRows) {

  if (!ws['!ref']) return;

  const range = XLSX.utils.decode_range(ws['!ref']);

  const hdr   = +headerRows || 0;

  const maxCols = range.e.c + 1;

  // Solid thin borders

  const thinBorder = { style: 'thin', color: { rgb: '000000' } };

  // Hair borders for internal gridlines in data cells

  const hairBorder = { style: 'hair', color: { rgb: '000000' } };

  // Find the headers in the table header row

  let headerRowIdx = hdr - 1;

  for (let r = Math.max(0, hdr - 3); r <= Math.min(range.e.r, hdr); r++) {

    const cRef = XLSX.utils.encode_cell({ r, c: 0 });

    if (ws[cRef] && String(ws[cRef].v).toUpperCase().trim() === 'STT') {

      headerRowIdx = r;

      break;

    }

  }

  const headers = [];

  for (let c = 0; c < maxCols; c++) {

    const cRef = XLSX.utils.encode_cell({ r: headerRowIdx, c });

    headers.push(ws[cRef] && ws[cRef].v ? String(ws[cRef].v).toUpperCase().trim() : '');

  }

  const subHeaders = [];

  if (headerRowIdx + 1 <= range.e.r) {

    for (let c = 0; c < maxCols; c++) {

      const cRef = XLSX.utils.encode_cell({ r: headerRowIdx + 1, c });

      subHeaders.push(ws[cRef] && ws[cRef].v ? String(ws[cRef].v).toUpperCase().trim() : '');

    }

  }

  for (let R = range.s.r; R <= range.e.r; R++) {

    for (let C = range.s.c; C <= range.e.c; C++) {

      const ref = XLSX.utils.encode_cell({ r: R, c: C });

      if (!ws[ref]) {

        if (R >= 8) ws[ref] = { t: 's', v: '' };

        else continue;

      }

      const cell = ws[ref];

      cell.s = cell.s || {};

      // Default font family is Times New Roman, size 12

      const font = { name: 'Times New Roman', sz: 12, color: { rgb: '000000' } };

      let fill = null;

      let alignment = { vertical: 'center' };

      let border = null;

      // ── Determine row category ──

      if (R < 8) {

        border = { top: null, bottom: null, left: null, right: null };

        if (R < 3 && C < 2) {

          font.sz = 14;

          font.bold = true;

          font.color = { rgb: '0A3D6B' }; // Navy brand color

          alignment.horizontal = 'center';

          alignment.vertical = 'center';

        } else if (R === 0) {

          font.sz = 24;

          font.bold = true;

          alignment.horizontal = 'center';

        } else if (R === 1 || R === 2) {

          font.sz = 14;

          font.bold = true;

          alignment.horizontal = 'center';

        } else if (R === 4 || R === 5) {

          font.bold = true;

          alignment.horizontal = 'left';

        } else if (R === 6) {

          font.bold = false;

          alignment.horizontal = 'left';

        }

      } else if (R < hdr) {

        // Table Header

        font.bold = true;

        alignment.horizontal = 'center';

        alignment.wrapText = true;

        fill = { type: 'pattern', patternType: 'solid', fgColor: { rgb: 'D9E1F2' } };

        border = { top: thinBorder, bottom: thinBorder, left: thinBorder, right: thinBorder };

      } else {

        // Data and total rows

        let isTotal = false;

        let isGroupHeader = false;

        let isSignatureTitle = false;

        let cellTextA = '';

        const cellARef = XLSX.utils.encode_cell({ r: R, c: 0 });

        if (ws[cellARef] && ws[cellARef].v) {

          cellTextA = String(ws[cellARef].v).toUpperCase().trim();

        }

        // Check if row contains signature keywords

        for (let colIdx = 0; colIdx < maxCols; colIdx++) {

          const cRef = XLSX.utils.encode_cell({ r: R, c: colIdx });

          const val = ws[cRef] ? ws[cRef].v : null;

          if (val && typeof val === 'string') {

            const vUpper = val.toUpperCase().trim();

            if (vUpper.includes('ĐẮK LẮK') || vUpper.includes('GIÁM ĐỐC') || vUpper.includes('ĐỒNG SÁNG LẬP') || vUpper.includes('VŨ THỊ KIM CHÚC') || vUpper.includes('KÝ XÁC NHẬN')) {

              isSignatureTitle = true;

            }

            if (vUpper.includes('CỘNG') || vUpper.includes('THÀNH TIỀN') || vUpper.includes('VAT') || vUpper.includes('THUẾ') || vUpper.includes('BẰNG CHỮ')) {

              isTotal = true;

            }

            if (vUpper.includes('PHÒNG') || vUpper.includes('CHI PHÍ KHÁC') || vUpper.includes('THIẾT BỊ ĐIỆN') || vUpper.includes('CHI TIẾT TỪ GHI CHÚ') || vUpper.includes('THIẾT BỊ NỘI THẤT') || vUpper.includes('PHẦN NƯỚC') || vUpper.includes('CHỐNG THẤM')) {

              isGroupHeader = true;

            }

          }

        }

        if (cellTextA && /^(I|II|III|IV|V|VI|VII|VIII|IX|X)$/.test(cellTextA)) {

          isGroupHeader = true;

        }

        if (isSignatureTitle) {

          border = { top: null, bottom: null, left: null, right: null };

          alignment.horizontal = 'center';

          const cRef = XLSX.utils.encode_cell({ r: R, c: C });

          const cellVal = ws[cRef] ? String(ws[cRef].v).toUpperCase() : '';

          if (cellVal.includes('KIM CHÚC') || cellVal.includes('GIÁM ĐỐC') || cellVal.includes('ĐỒNG SÁNG LẬP') || cellVal.includes('VŨ THỊ')) {

            if (cellVal.includes('KIM CHÚC') || cellVal.includes('VŨ THỊ')) {

              font.bold = true;

            }

            alignment.horizontal = 'center';

          }

        } else if (isTotal) {

          // Total row background `#D9E2F3`

          const rowValues = [];

          for (let colIdx = 0; colIdx < maxCols; colIdx++) {

            const cRef = XLSX.utils.encode_cell({ r: R, c: colIdx });

            if (ws[cRef] && ws[cRef].v) rowValues.push(String(ws[cRef].v).toUpperCase().trim());

          }

          const isBC = rowValues.some(v => v.includes('BẰNG CHỮ'));

          if (isBC) {

            fill = null;

            font.bold = true;

            border = { top: thinBorder, bottom: null, left: thinBorder, right: thinBorder };

            alignment.horizontal = 'left';

          } else {

            fill = { type: 'pattern', patternType: 'solid', fgColor: { rgb: 'D9E2F3' } };

            font.bold = true;

            border = { top: thinBorder, bottom: thinBorder, left: thinBorder, right: thinBorder };

            if (C === maxCols - 1 || C === maxCols - 2) {

              alignment.horizontal = 'right';

            } else {

              alignment.horizontal = C === 0 ? 'center' : 'left';

            }

          }

        } else if (isGroupHeader) {

          font.bold = true;

          border = { top: thinBorder, bottom: thinBorder, left: thinBorder, right: thinBorder };

          alignment.horizontal = C === 0 ? 'center' : 'left';

        } else {

          // Regular item row

          border = { top: hairBorder, bottom: hairBorder, left: thinBorder, right: thinBorder };

          const h = headers[C] || '';

          const sh = subHeaders[C] || '';

          if (h === 'STT') {

            alignment.horizontal = 'center';

          } else if (h.includes('HẠNG MỤC') || h.includes('TÊN VẬT TƯ') || h.includes('VẬT TƯ')) {

            alignment.horizontal = 'left';

          } else if (h.includes('Đ. VỊ') || h.includes('ĐVT') || h.includes('Đ.VỊ')) {

            alignment.horizontal = 'center';

          } else if (h.includes('GHI CHÚ') || h.includes('NHÀ CUNG CẤP') || h.includes('PHÒNG SỬ DỤNG')) {

            alignment.horizontal = 'left';

          } else if (sh === 'DÀI' || sh === 'RỘNG' || sh === 'CAO') {

            alignment.horizontal = 'center';

          } else if (h.includes('SỐ LƯỢNG') || h.includes('TỔNG SL') || h.includes('KL') || h.includes('SL') || h.includes('LƯỢNG')) {

            alignment.horizontal = 'right';

          } else if (h.includes('ĐƠN GIÁ')) {

            alignment.horizontal = 'right';

          } else if (h.includes('THÀNH TIỀN')) {

            alignment.horizontal = 'right';

          } else {

            alignment.horizontal = 'right';

          }

        }

      }

      cell.s.font = font;

      if (fill) cell.s.fill = fill;

      cell.s.alignment = alignment;

      if (border) cell.s.border = border;

    }

  }

}

// Helper: chuyển string nhị phân sang ArrayBuffer (dùng cho xlsx-style write)

function s2ab(s) {

  const buf  = new ArrayBuffer(s.length);

  const view = new Uint8Array(buf);

  for (let i = 0; i < s.length; i++) view[i] = s.charCodeAt(i) & 0xFF;

  return buf;

}

// Ghi workbook dưới dạng file xlsx (tương thích xlsx-style)

// Áp dụng cell styles (font, fill, alignment) cho toàn sheet theo chuẩn FILE MẪU

// headerDataRow: row index (0-based) của dòng đầu tiên có data (thường row 8 = index 8)

function applySheetStyles(ws, headerDataRow, sheetType) {

  const romanSet = new Set(['I','II','III','IV','V','VI','VII','VIII','IX','X','XI','XII','XIII','XIV','XV','XVI','XVII','XVIII','XIX','XX']);

  if (!ws['!ref']) return;

  const range = XLSX.utils.decode_range(ws['!ref']);

  // Màu nền header bảng = theme:8 tint:0.8 ≈ #BDD7EE (xanh nhạt Excel)

  const HDR_BG  = 'BDD7EE';

  const WHITE   = 'FFFFFF';

  // Font mặc định toàn sheet: Times New Roman 12

  const baseFont = { name: 'Times New Roman', sz: 12, bold: false, color: { rgb: '000000' } };

  const boldFont = { name: 'Times New Roman', sz: 12, bold: true,  color: { rgb: '000000' } };

  // Borders

  const solidBlack  = { style: 'thin',   color: { rgb: '000000' } };

  const solidMedium = { style: 'medium', color: { rgb: '000000' } };

  const dashedBlack = { style: 'dashed', color: { rgb: '000000' } };

  const hdrRow = (headerDataRow !== undefined) ? headerDataRow : 8; // row index 8,9 = Excel row 9,10

  const totalRows = new Set();

  let footerStartRow = 9999;

  let signatureStartRow = 9999;

  for (let r = range.s.r; r <= range.e.r; r++) {

    for (let c = range.s.c; c <= range.e.c; c++) {

      const cellRef = XLSX.utils.encode_cell({ r: r, c: c });

      if (ws[cellRef] && ws[cellRef].v !== undefined) {

        const valStr = String(ws[cellRef].v).trim();

        const valLower = valStr.toLowerCase();

        if (

          valLower.includes('thành tiền (trước vat)') ||

          valLower.includes('cộng trước vat') ||

          valLower.includes('thuế vat') ||

          valLower.startsWith('vat') ||

          valLower.includes('tổng cộng') ||

          valLower.includes('tổng cộng vật tư (theo dự toán)')

        ) {

          totalRows.add(r);

        }

        if (

          valLower.startsWith('bằng chữ:') ||

          valStr.startsWith('*') ||

          valLower.includes('xác nhận của khách') ||

          valLower.includes('xác nhận của kh') ||

          valLower.includes('người lập bảng') ||

          valLower.startsWith('tp. hcm ngày') ||

          valLower.startsWith('tp.hcm ngày')

        ) {

          if (r < footerStartRow) {

            footerStartRow = r;

          }

        }

        if (

          valLower.includes('xác nhận của khách') ||

          valLower.includes('xác nhận của kh') ||

          valLower.includes('người lập bảng') ||

          valLower === 'giám đốc' ||

          valLower.includes('vũ thị kim chúc')

        ) {

          if (r < signatureStartRow) {

            signatureStartRow = r;

          }

        }

      }

    }

  }

  for (let R = range.s.r; R <= range.e.r; R++) {

    for (let C = range.s.c; C <= range.e.c; C++) {

      const ref = XLSX.utils.encode_cell({ r: R, c: C });

      if (!ws[ref]) ws[ref] = { t: 's', v: '' };

      ws[ref].s = ws[ref].s || {};

      const val = ws[ref].v ? String(ws[ref].v).trim() : '';

      const isHeaderRow  = (sheetType === 'detail') ? (R === hdrRow || R === hdrRow + 1) : (R === hdrRow);

      const isTitleRow   = (R < 8); // Các dòng tiêu đề phía trên

      const isBigTitle   = (R === 0); // Dòng tiêu đề lớn nhất (Times 24 bold)

      const isMedTitle   = (R === 1 || R === 2); // Times 14 bold

      // Font

      let font;

      if (isBigTitle) {

        font = { name: 'Times New Roman', sz: 20, bold: true, color: { rgb: '000000' } };

      } else if (isMedTitle) {

        font = { name: 'Times New Roman', sz: 14, bold: true, color: { rgb: '000000' } };

      } else if (isHeaderRow) {

        font = { ...boldFont };

      } else if (isTitleRow && (R === 4 || R === 5)) {

        font = { ...boldFont };

      } else {

        font = { ...baseFont };

      }

      ws[ref].s.font = font;

    if (val === 'Xác nhận của khách hàng' || val === 'Người lập bảng' || val === 'Giám đốc' || val === 'VŨ THỊ KIM CHÚC' || val.startsWith('Bằng chữ:') || val === 'TỔNG CỘNG' || val.startsWith('TỔNG CỘNG VẬT TƯ')) {

      ws[ref].s.font = { name: 'Times New Roman', sz: 12, bold: true, color: { rgb: '000000' } };

    } else if (val.startsWith('Báo giá trên có giá trị') || val.startsWith('_ Báo giá trên') || val.startsWith('_ Thời gian thi công') || val.startsWith('TP. HCM ngày ......')) {

      ws[ref].s.font = { name: 'Times New Roman', sz: 11, italic: true, color: { rgb: '000000' } };

    }

      // Fill

      if (R < hdrRow) {

        ws[ref].s.fill = { patternType: 'solid', fgColor: { rgb: WHITE }, bgColor: { rgb: WHITE } };

      } else if (R >= footerStartRow) {

        ws[ref].s.fill = { patternType: 'solid', fgColor: { rgb: WHITE }, bgColor: { rgb: WHITE } };

      } else if (isHeaderRow) {

        ws[ref].s.fill = { patternType: 'solid', fgColor: { rgb: HDR_BG }, bgColor: { rgb: HDR_BG } };

      }

      // Alignment

      if (sheetType === 'detail' && totalRows.has(R)) {

        if (C < 8) {

          ws[ref].s.alignment = { horizontal: 'center', vertical: 'center', wrapText: true };

        } else if (C === 8) {

          ws[ref].s.alignment = { horizontal: 'right', vertical: 'center', wrapText: true };

        } else {

          ws[ref].s.alignment = { horizontal: 'left', vertical: 'center', wrapText: true };

        }

      } else if (sheetType === 'vt' && totalRows.has(R)) {

        if (C < 6) {

          ws[ref].s.alignment = { horizontal: 'center', vertical: 'center', wrapText: true };

        } else if (C === 6) {

          ws[ref].s.alignment = { horizontal: 'right', vertical: 'center', wrapText: true };

        } else {

          ws[ref].s.alignment = { horizontal: 'left', vertical: 'center', wrapText: true };

        }

      } else if (sheetType === 'sum' && totalRows.has(R)) {

        if (C < 6) {

          ws[ref].s.alignment = { horizontal: 'center', vertical: 'center', wrapText: true };

        } else if (C === 6) {

          ws[ref].s.alignment = { horizontal: 'right', vertical: 'center', wrapText: true };

        } else {

          ws[ref].s.alignment = { horizontal: 'left', vertical: 'center', wrapText: true };

        }

      } else if (R >= signatureStartRow) {

        if (val === 'Xác nhận của khách hàng' || val === 'Người lập bảng') {

          ws[ref].s.alignment = { horizontal: 'left', vertical: 'center', wrapText: true };

        } else {

          ws[ref].s.alignment = { horizontal: 'center', vertical: 'center', wrapText: true };

        }

      } else if (R >= footerStartRow) {

        if (val === 'Giám đốc' || val === 'VŨ THỊ KIM CHÚC' || val.startsWith('TP. HCM ngày ......')) {

          ws[ref].s.alignment = { horizontal: 'center', vertical: 'center', wrapText: true };

        } else {

          ws[ref].s.alignment = { horizontal: 'left', vertical: 'center', wrapText: true };

        }

      } else if (R === 4 || R === 5 || R === 6) {

        ws[ref].s.alignment = { horizontal: 'left', vertical: 'center', wrapText: true };

      } else if (R === 0 || R === 1 || R === 2) {

        ws[ref].s.alignment = { horizontal: 'center', vertical: 'center', wrapText: false };

      } else if (isHeaderRow) {

        ws[ref].s.alignment = { horizontal: 'center', vertical: 'center', wrapText: true };

      } else if (val === 'Giám đốc' || val === 'VŨ THỊ KIM CHÚC' || val.startsWith('TP. HCM ngày ......')) {

      ws[ref].s.alignment = { horizontal: 'center', vertical: 'center', wrapText: true };

    } else if (val === 'Xác nhận của khách hàng') {

      ws[ref].s.alignment = { horizontal: 'left', vertical: 'center', wrapText: true };

    } else if (sheetType === 'detail') {

      if (C === 0) {

        ws[ref].s.alignment = { horizontal: 'center', vertical: 'center', wrapText: true };

      } else if (C === 1) {

        const cellA = ws[XLSX.utils.encode_cell({r: R, c: 0})];

        const valA = cellA ? String(cellA.v || '').trim() : '';

        const isSectionHeader = romanSet.has(valA);

        if (!isTitleRow && !isHeaderRow && R < footerStartRow && !isSectionHeader && val !== '') {

          ws[ref].s.alignment = { horizontal: 'left', vertical: 'center', wrapText: true, indent: 1 };

        } else {

          ws[ref].s.alignment = { horizontal: 'left', vertical: 'center', wrapText: true };

        }

      } else if (C >= 2 && C <= 5) {

        ws[ref].s.alignment = { horizontal: 'center', vertical: 'center', wrapText: true };

      } else if (C >= 6 && C <= 9) {

        ws[ref].s.alignment = { horizontal: 'right', vertical: 'center', wrapText: true };

      }

    } else if (sheetType === 'vt') {

      if (C === 0) {

        ws[ref].s.alignment = { horizontal: 'center', vertical: 'center', wrapText: true };

      } else if (C === 1) {

        const cellA = ws[XLSX.utils.encode_cell({r: R, c: 0})];

        const valA = cellA ? String(cellA.v || '').trim() : '';

        const isSectionHeader = romanSet.has(valA);

        if (!isTitleRow && !isHeaderRow && R < footerStartRow && !isSectionHeader && val !== '') {

          ws[ref].s.alignment = { horizontal: 'left', vertical: 'center', wrapText: true, indent: 1 };

        } else {

          ws[ref].s.alignment = { horizontal: 'left', vertical: 'center', wrapText: true };

        }

      } else if (C === 2) {

        ws[ref].s.alignment = { horizontal: 'center', vertical: 'center', wrapText: true };

      } else if (C >= 3 && C <= 6) {

        ws[ref].s.alignment = { horizontal: 'right', vertical: 'center', wrapText: true };

      } else {

        ws[ref].s.alignment = { horizontal: 'left', vertical: 'center', wrapText: true };

      }

    } else {

      if (C === 0) {

        ws[ref].s.alignment = { horizontal: 'center', vertical: 'center', wrapText: true };

      } else if (C === 1) {

        const cellA = ws[XLSX.utils.encode_cell({r: R, c: 0})];

        const valA = cellA ? String(cellA.v || '').trim() : '';

        const isSectionHeader = romanSet.has(valA);

        if (sheetType === 'sum' && !isTitleRow && !isHeaderRow && R < footerStartRow && !isSectionHeader && val !== '') {

          ws[ref].s.alignment = { horizontal: 'left', vertical: 'center', wrapText: true, indent: 1 };

        } else {

          ws[ref].s.alignment = { horizontal: 'left', vertical: 'center', wrapText: true };

        }

      } else if (C === 2) {

        ws[ref].s.alignment = { horizontal: 'center', vertical: 'center', wrapText: true };

      } else if (C >= 3) {

        ws[ref].s.alignment = { horizontal: 'right', vertical: 'center', wrapText: true };

      }

    }

      // Formatting number of decimal places to exactly 2 for Quantity/Calculated Qty/Purchase Qty columns

      if (ws[ref] && ws[ref].t === 'n') {

        // Only format numeric cells

      }

      if (sheetType === 'detail' && C === 6 && R >= hdrRow + 2 && R < footerStartRow) {

        ws[ref].z = '#,##0.00';

      } else if (sheetType === 'sum' && C >= 3 && C <= range.e.c - 3 && R >= hdrRow + 1 && R < footerStartRow) {

        ws[ref].z = '#,##0.00';

      } else if (sheetType === 'vt' && (C === 3 || C === 4) && R >= hdrRow + 1 && R < footerStartRow) {

        ws[ref].z = '#,##0.00';

      }

      // Borders

      if (R < hdrRow) {

        ws[ref].s.border = {

          top:    { style: 'none' },

          bottom: { style: 'none' },

          left:   { style: 'none' },

          right:  { style: 'none' },

        };

      } else {

        if (R >= footerStartRow) {

          ws[ref].s.border = {

            top:    { style: 'none' },

            bottom: { style: 'none' },

            left:   { style: 'none' },

            right:  { style: 'none' },

          };

        } else if (totalRows.has(R)) {

          ws[ref].s.border = {

            top:    solidBlack,

            bottom: solidBlack,

            left:   solidBlack,

            right:  solidBlack,

          };

        } else if (isHeaderRow) {

          ws[ref].s.border = {

            top: solidMedium, bottom: solidMedium,

            left: solidMedium, right: solidMedium,

          };

        } else {

          ws[ref].s.border = {

            top:    dashedBlack,

            bottom: dashedBlack,

            left:   solidBlack,

            right:  solidBlack,

          };

        }

      }

    }

  }

}

  // Helper: bold cho section header rows

  function applyBoldSectionRows(ws, hdrDataRow, colOffset = 0) {

    if (!ws['!ref']) return;

    const romanSet = new Set(['I','II','III','IV','V','VI','VII','VIII',

      'IX','X','XI','XII','XIII','XIV','XV','XVI','XVII','XVIII','XIX','XX']);

    const range = XLSX.utils.decode_range(ws['!ref']);

    const startRow = (hdrDataRow !== undefined ? hdrDataRow : 8) + 2;

    for (let R = startRow; R <= range.e.r; R++) {

      const cellA = ws[XLSX.utils.encode_cell({r: R, c: colOffset})];

      const valA = cellA ? String(cellA.v || '').trim() : '';

      const cellB = ws[XLSX.utils.encode_cell({r: R, c: colOffset + 1})];

      const valB = cellB ? String(cellB.v || '') : '';

      let isSection = romanSet.has(valA);

      if (!isSection && valA === '') {

        let allEmpty = true;

        for (let c = colOffset + 2; c <= Math.min(range.e.c, 8 + colOffset); c++) {

          const cv = ws[XLSX.utils.encode_cell({r: R, c})];

          if (cv && cv.v !== '' && cv.v !== undefined) { allEmpty = false; break; }

        }

        if (allEmpty && valB && valB === valB.toUpperCase() && valB.trim().length > 2 && !valB.toLowerCase().includes('tổng cộng')) isSection = true;

      }

      if (isSection) {

        for (let C = range.s.c; C <= range.e.c; C++) {

          const ref = XLSX.utils.encode_cell({r: R, c: C});

          if (!ws[ref]) ws[ref] = { t: 's', v: '' };

          ws[ref].s = ws[ref].s || {};

          ws[ref].s.font = { name: 'Times New Roman', sz: 12, bold: true, color: { rgb: '000000' } };

          // Outside borders for section row

          ws[ref].s.border = {

            top:    { style: 'thin', color: { rgb: '000000' } },

            bottom: { style: 'thin', color: { rgb: '000000' } },

            left:   C === range.s.c ? { style: 'thin', color: { rgb: '000000' } } : { style: 'none' },

            right:  C === range.e.c ? { style: 'thin', color: { rgb: '000000' } } : { style: 'none' },

          };

          // Alignments for section row

          if (C === colOffset) {

            ws[ref].s.alignment = { horizontal: 'center', vertical: 'center', wrapText: false };

          } else if (C === colOffset + 1) {

            ws[ref].s.alignment = { horizontal: 'left', vertical: 'center', wrapText: false };

          } else {

            ws[ref].s.alignment = { horizontal: 'center', vertical: 'center', wrapText: false };

          }

        }

      }

    }

  }

function xlsxWriteSheetJS(wb, fileName) {
  try {
    if (typeof XLSX === 'undefined') {
      throw new Error('Thư viện SheetJS (XLSX) chưa được tải thành công.');
    }
    // Ghi workbook ra định dạng binary string
    const out = XLSX.write(wb, { bookType: 'xlsx', bookSST: false, type: 'binary' });
    // Chuyển binary string sang Blob nhị phân
    const blob = new Blob([s2ab(out)], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
    
    // Tải file tương thích tốt trên PC và điện thoại (Android/iOS)
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = fileName;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  } catch (err) {
    console.error('Lỗi khi xuất file Excel:', err);
    alert('❌ Lỗi khi xuất file Excel: ' + err.message);
  }
}

async function xlsxWritePhotos(project, fileName) {
  if (typeof ExcelJS === 'undefined') {
    throw new Error('Thư viện ExcelJS chưa được tải thành công.');
  }

  const workbook = new ExcelJS.Workbook();
  const rooms = project.rooms || [];
  const categories = ['overview', 'den', 'tudien', 'maylanh', 'noithat', 'wc', 'other'];
  const catLabels = {
    overview: 'ẢNH TOÀN CẢNH KHẢO SÁT',
    den: 'ĐÈN CHIẾU SÁNG',
    tudien: 'TỦ ĐIỆN & PHỤ KIỆN',
    maylanh: 'MÁY LẠNH & THÔNG GIÓ',
    noithat: 'NỘI THẤT',
    wc: 'THIẾT BỊ VỆ SINH',
    other: 'KHÁC'
  };

  // Tính tổng số lượng ảnh phục vụ thanh tiến trình
  let totalPhotos = 0;
  rooms.forEach(room => {
    if (room.photos) {
      categories.forEach(cat => {
        totalPhotos += (room.photos[cat] || []).length;
      });
    }
  });

  const btn = document.querySelector('.bottom-nav .nav-tab[data-tab="export"]');
  let processedCount = 0;

  function toRoman(num) {
    const roman = ['I', 'II', 'III', 'IV', 'V', 'VI', 'VII', 'VIII', 'IX', 'X', 'XI', 'XII'];
    return roman[num - 1] || num;
  }

  // Helper để đọc kích thước thật của ảnh từ Blob
  const getBlobDimensions = (blob) => {
    return new Promise((resolve) => {
      const url = URL.createObjectURL(blob);
      const img = new Image();
      const timer = setTimeout(() => {
        resolve({ w: 300, h: 400 });
        URL.revokeObjectURL(url);
      }, 2000);
      img.onload = () => {
        clearTimeout(timer);
        resolve({ w: img.naturalWidth, h: img.naturalHeight });
        URL.revokeObjectURL(url);
      };
      img.onerror = () => {
        clearTimeout(timer);
        resolve({ w: 300, h: 400 });
        URL.revokeObjectURL(url);
      };
      img.src = url;
    });
  };

  // Helper để đọc kích thước thật của ảnh từ base64
  const getBase64Dimensions = (base64Str) => {
    return new Promise((resolve) => {
      const img = new Image();
      const timer = setTimeout(() => {
        resolve({ w: 300, h: 400 });
      }, 2000);
      img.onload = () => {
        clearTimeout(timer);
        resolve({ w: img.naturalWidth, h: img.naturalHeight });
      };
      img.onerror = () => {
        clearTimeout(timer);
        resolve({ w: 300, h: 400 });
      };
      img.src = base64Str;
    });
  };

  // Helper nén và resize ảnh bằng canvas
  const resizeAndCompressImage = (srcUrl, resizeW, resizeH, quality = 0.6) => {
    return new Promise((resolve) => {
      const img = new Image();
      const timer = setTimeout(() => resolve(null), 5000);
      img.onload = () => {
        clearTimeout(timer);
        const canvas = document.createElement('canvas');
        canvas.width = resizeW;
        canvas.height = resizeH;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, resizeW, resizeH);
        try {
          const dataUrl = canvas.toDataURL('image/jpeg', quality);
          resolve(dataUrl.split(',')[1]);
        } catch (e) {
          resolve(null);
        }
      };
      img.onerror = () => {
        clearTimeout(timer);
        resolve(null);
      };
      img.src = srcUrl;
    });
  };

  for (let rIdx = 0; rIdx < rooms.length; rIdx++) {
    const room = rooms[rIdx];
    const sheetName = sanitizeSheetName(room.name, rIdx);
    const sheetImg = workbook.addWorksheet(sheetName);
    
    // Thiết lập cấu trúc cột (10 cột để khớp khối header)
    sheetImg.columns = [
      { key: 'colA', width: 8 },   // STT
      { key: 'colB', width: 45 },  // Ảnh hiện trạng (sẽ được tự co giãn dựa trên cỡ ảnh thực tế ở dưới)
      { key: 'colC', width: 10 },
      { key: 'colD', width: 10 },
      { key: 'colE', width: 10 },
      { key: 'colF', width: 10 },
      { key: 'colG', width: 10 },
      { key: 'colH', width: 10 },
      { key: 'colI', width: 10 },
      { key: 'colJ', width: 15 }   // Cột C->J gộp lại cho ghi chú
    ];
    sheetImg.views = [{ showGridLines: true }];

    // --- 1. VẼ KHỐI HEADER TIÊU CHUẨN ĐẦU MỖI SHEET PHÒNG (Sửa lỗi lặp) ---
    const r1 = sheetImg.addRow(['', '', (project.subtitle || project.name || '').toUpperCase()]);
    const r2 = sheetImg.addRow(['', '', `CÔNG TRÌNH: ${project.client || ''}`.toUpperCase()]);
    sheetImg.addRow([]); // Dòng 3 trống
    const r4 = sheetImg.addRow([`Từ : ${project.sender || ''}`, '', '', '', `Kính gởi: ${project.recipient || ''}`]);
    const r5 = sheetImg.addRow([`Công Ty: ${project.company || ''}`, '', '', '', `Công Ty: ${project.clientCo || ''}`]);
    const r6 = sheetImg.addRow([`Địa chỉ : ${project.companyAddr || ''}`, '', '', '', `Địa chỉ : ${project.clientAddr || project.address || ''}`]);
    sheetImg.addRow([]); // Dòng 7 trống

    sheetImg.mergeCells('C1:J1');
    sheetImg.mergeCells('C2:J2');
    sheetImg.mergeCells('A4:D4');
    sheetImg.mergeCells('E4:J4');
    sheetImg.mergeCells('A5:D5');
    sheetImg.mergeCells('E5:J5');
    sheetImg.mergeCells('A6:D6');
    sheetImg.mergeCells('E6:J6');

    r1.getCell(3).font = { name: 'Times New Roman', sz: 16, bold: true, color: { argb: 'FF000000' } };
    r1.getCell(3).alignment = { vertical: 'middle', horizontal: 'center' };
    r1.height = 25;

    r2.getCell(3).font = { name: 'Times New Roman', sz: 12, bold: true, color: { argb: 'FF000000' } };
    r2.getCell(3).alignment = { vertical: 'middle', horizontal: 'center' };
    r2.height = 20;

    [r4, r5, r6].forEach(r => {
      r.getCell(1).font = { name: 'Times New Roman', sz: 12, bold: true, color: { argb: 'FF000000' } };
      r.getCell(1).alignment = { vertical: 'middle', horizontal: 'left' };
      r.getCell(5).font = { name: 'Times New Roman', sz: 12, color: { argb: 'FF000000' } };
      r.getCell(5).alignment = { vertical: 'middle', horizontal: 'left' };
      r.height = 18;
    });

    // Dòng "THƯ VIỆN HÌNH ẢNH" nằm trên header phòng
    const r8 = sheetImg.addRow(['', '', 'THƯ VIỆN HÌNH ẢNH']);
    sheetImg.mergeCells('C8:J8');
    r8.getCell(3).font = { name: 'Times New Roman', sz: 14, bold: true, color: { argb: 'FF1B3A5C' } };
    r8.getCell(3).alignment = { vertical: 'middle', horizontal: 'center' };
    r8.height = 26;

    // Header tên phòng (giữ nguyên nền xanh đậm chữ trắng)
    const roomCode = String(rIdx + 1).padStart(2, '0');
    const area = room.D && room.R ? ((room.D * room.R) / 1000000).toFixed(1) : '0.0';
    const roomHeaderName = `PHÒNG ${roomCode} — ${(room.name || '').toUpperCase()} (${area} m²)`;
    const roomHeaderRow = sheetImg.addRow([roomHeaderName]);
    sheetImg.mergeCells(`A${roomHeaderRow.number}:J${roomHeaderRow.number}`);
    roomHeaderRow.getCell(1).fill = {
      type: 'pattern',
      pattern: 'solid',
      fgColor: { argb: 'FF1B3A5C' }
    };
    roomHeaderRow.getCell(1).font = { name: 'Times New Roman', sz: 12, bold: true, color: { argb: 'FFFFFFFF' } };
    roomHeaderRow.getCell(1).alignment = { vertical: 'middle', horizontal: 'left', indent: 1 };
    roomHeaderRow.height = 25;

    // Phân loại nhóm ảnh trong phòng
    const activeGroups = [];
    categories.forEach(cat => {
      const list = room.photos?.[cat] || [];
      if (list.length > 0) {
        let minTime = Infinity;
        list.forEach(p => {
          const t = p.date ? new Date(p.date).getTime() : Date.now();
          if (t < minTime) minTime = t;
        });
        activeGroups.push({
          cat,
          label: catLabels[cat],
          photos: list,
          minTime
        });
      }
    });

    // Sắp xếp thứ tự nhóm theo thời gian up ảnh
    activeGroups.sort((a, b) => a.minTime - b.minTime);

    const colMaxW = {}; // Để theo dõi chiều rộng ảnh lớn nhất cho cột B->G (index 1->6)

    if (activeGroups.length === 0) {
      const noPhotoRow = sheetImg.addRow(['', 'Chưa có hình ảnh', '']);
      sheetImg.mergeCells(`B${noPhotoRow.number}:J${noPhotoRow.number}`);
      noPhotoRow.getCell(2).font = { name: 'Times New Roman', sz: 11, italic: true, color: { argb: 'FF9CA3AF' } };
      noPhotoRow.getCell(2).alignment = { vertical: 'middle', horizontal: 'left' };
      noPhotoRow.height = 20;
    } else {
      for (let gIdx = 0; gIdx < activeGroups.length; gIdx++) {
        const group = activeGroups[gIdx];
        
        // Đề mục số La Mã
        const groupHeaderRow = sheetImg.addRow(['', `${toRoman(gIdx + 1)}. ${group.label}`, '']);
        sheetImg.mergeCells(`B${groupHeaderRow.number}:J${groupHeaderRow.number}`);
        groupHeaderRow.getCell(2).font = { name: 'Times New Roman', sz: 11, bold: true, color: { argb: 'FF1B3A5C' } };
        groupHeaderRow.getCell(2).alignment = { vertical: 'middle', horizontal: 'left' };
        groupHeaderRow.height = 22;

        // Chia ảnh thành các chunk tối đa 6 ảnh
        const chunks = [];
        for (let i = 0; i < group.photos.length; i += 6) {
          chunks.push(group.photos.slice(i, i + 6));
        }

        for (let cIdx = 0; cIdx < chunks.length; cIdx++) {
          const chunk = chunks[cIdx];
          
          // Dòng chứa ảnh
          const photoRow = sheetImg.addRow([]);
          
          // Dòng chứa ghi chú ngay dưới dòng ảnh
          const noteRow = sheetImg.addRow([]);

          let maxHInRow = 40; // minimum height
          
          for (let pIdx = 0; pIdx < chunk.length; pIdx++) {
            const photo = chunk[pIdx];
            const colIdx = 1 + pIdx; // index 1 is Column B, index 2 is Column C, etc.
            
            try {
              processedCount++;
              if (btn) {
                btn.innerHTML = `<i data-lucide="loader" class="spin"></i> <span>Ảnh ${processedCount}/${totalPhotos}</span>`;
                if (window.lucide) window.lucide.createIcons();
              }
              let base64 = '';
              let imgW = 300;
              let imgH = 400;
              let rawSrc = '';
              let isBlobUrl = false;

              if (photo.data && photo.data.startsWith('data:')) {
                rawSrc = photo.data;
                const size = await getBase64Dimensions(photo.data);
                imgW = size.w;
                imgH = size.h;
              } else if (photo.id) {
                const blob = await PhotoDB.getPhoto(photo.id);
                if (blob) {
                  let finalBlob = blob;
                  const isHeic = await isBlobHEIC(blob);
                  if (isHeic && typeof heic2any === 'function') {
                    try {
                      const converted = await heic2any({ blob, toType: 'image/jpeg', quality: 0.7 });
                      finalBlob = Array.isArray(converted) ? converted[0] : converted;
                    } catch (heicErr) {
                      console.warn('heic2any failed, fallback to raw blob:', heicErr);
                    }
                  }
                  rawSrc = URL.createObjectURL(finalBlob);
                  isBlobUrl = true;
                  const size = await getBlobDimensions(finalBlob);
                  imgW = size.w;
                  imgH = size.h;
                }
              }

              if (rawSrc) {
                // --- 1. CỠ ẢNH HIỂN THỊ = 1/20 ẢNH GỐC ---
                const targetW = imgW / 20;
                const targetH = imgH / 20;

                // --- 2. NÉN ẢNH MẠNH HƠN KHI NHÚNG VÀO EXCEL (resize = display * 2, quality 0.6) ---
                const resizeW = Math.round(targetW * 2);
                const resizeH = Math.round(targetH * 2);

                base64 = await resizeAndCompressImage(rawSrc, resizeW, resizeH, 0.6);
                if (isBlobUrl) {
                  URL.revokeObjectURL(rawSrc);
                }

                if (base64) {
                  // Ghi nhận kích thước rộng nhất của cột (để set độ rộng cột B->G sau này)
                  colMaxW[colIdx] = Math.max(colMaxW[colIdx] || 0, targetW);

                  // Dò tìm chiều cao lớn nhất cho dòng chứa ảnh (quy đổi pixel sang points: 1px = 0.75pt)
                  const rowHInPoints = targetH * 0.75 + 10;
                  if (rowHInPoints > maxHInRow) {
                    maxHInRow = rowHInPoints;
                  }

                  const imageId = workbook.addImage({
                    base64: base64,
                    extension: 'jpeg'
                  });

                  // Nhúng ảnh vào cột tương ứng (col: colIdx, row: photoRow.number - 1)
                  sheetImg.addImage(imageId, {
                    tl: { col: colIdx, row: photoRow.number - 1, colOff: 5 * 9525, rowOff: 5 * 9525 },
                    ext: { width: targetW, height: targetH }
                  });

                  // Ghi chú ngay dòng bên dưới, cùng cột
                  const dateStr = photo.date ? new Date(photo.date).toLocaleDateString('vi-VN') : 'Không rõ';
                  const noteText = `${photo.name}\n(${dateStr})`;
                  
                  const noteCell = noteRow.getCell(colIdx + 1);
                  noteCell.value = noteText;
                  noteCell.font = { name: 'Times New Roman', sz: 9, color: { argb: 'FF4B5563' } };
                  noteCell.alignment = { vertical: 'top', horizontal: 'center', wrapText: true };
                } else {
                  photoRow.getCell(colIdx + 1).value = '(ảnh lỗi)';
                  photoRow.getCell(colIdx + 1).font = { name: 'Times New Roman', sz: 10, italic: true, color: { argb: 'FFEF4444' } };
                  photoRow.getCell(colIdx + 1).alignment = { vertical: 'middle', horizontal: 'center' };
                }
              }
            } catch (err) {
              console.warn('Lỗi chèn ảnh:', err);
            }
          }

          // Thiết lập chiều cao dòng ảnh và dòng ghi chú
          photoRow.height = maxHInRow;
          noteRow.height = 30; // Đủ 2 dòng ghi chú chữ 9pt

          // Vẽ viền cho các ô chứa ảnh & ghi chú
          for (let pIdx = 0; pIdx < chunk.length; pIdx++) {
            const colIdx = 1 + pIdx;
            const pCell = photoRow.getCell(colIdx + 1);
            const nCell = noteRow.getCell(colIdx + 1);

            pCell.border = {
              top: { style: 'thin', color: { argb: 'FFE5E7EB' } },
              bottom: { style: 'thin', color: { argb: 'FFE5E7EB' } },
              left: { style: 'thin', color: { argb: 'FFE5E7EB' } },
              right: { style: 'thin', color: { argb: 'FFE5E7EB' } }
            };
            nCell.border = {
              top: { style: 'thin', color: { argb: 'FFE5E7EB' } },
              bottom: { style: 'thin', color: { argb: 'FFE5E7EB' } },
              left: { style: 'thin', color: { argb: 'FFE5E7EB' } },
              right: { style: 'thin', color: { argb: 'FFE5E7EB' } }
            };
          }

          sheetImg.addRow([]); // Dòng trống cách giữa các hàng ảnh
        }
      }
    }

    // Thiết lập độ rộng cột B đến G dựa trên kích thước ảnh rộng nhất của từng cột (+ đệm)
    for (let c = 1; c <= 6; c++) {
      const maxW = colMaxW[c] || 0;
      if (maxW > 0) {
        sheetImg.getColumn(c + 1).width = Math.max(maxW / 7.2 + 4, 18);
      } else {
        sheetImg.getColumn(c + 1).width = 18;
      }
    }
  }

  // Cập nhật trạng thái lưu file Excel
  if (btn) {
    btn.innerHTML = `<i data-lucide="loader" class="spin"></i> Đang tạo file Excel...`;
    if (window.lucide) window.lucide.createIcons();
  }

  // Ghi tệp ExcelJS và kích hoạt tải về điện thoại/PC
  const finalBuffer = await workbook.xlsx.writeBuffer();
  const fileBlob = new Blob([finalBuffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
  const url = URL.createObjectURL(fileBlob);
  const a = document.createElement('a');
  a.href = url;
  a.download = fileName;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}



export function generateWorkbook(project) {

  if (!project.rooms || project.rooms.length === 0) {

    alert('Chưa có dữ liệu để xuất. Hãy thêm phòng trước!');

    return;

  }

  if (!window.XLSX) {

    alert('Thư viện xuất Excel chưa tải xong. Vui lòng thử lại sau vài giây!');

    return;

  }

  const wb = XLSX.utils.book_new();

  const roomSheets = [];

  // Hàm phụ tạo khung Header cho mỗi sheet

  const buildHeader = (aoaArray, mergesArray, title, maxCols, colOffset = 0) => {

    const blk = () => Array(maxCols).fill('');

    // Row 0 (Excel row 1): Tiêu đề chính — center từ C(idx 2) đến hết

    const r0 = blk(); r0[2 + colOffset] = title.toUpperCase(); aoaArray.push(r0);

    // Row 1 (Excel row 2): Subtitle / tên dự án

    const r1 = blk(); r1[2 + colOffset] = (project.subtitle || project.name || '').toUpperCase(); aoaArray.push(r1);

    // Row 2 (Excel row 3): CÔNG TRÌNH: [tên]

    const r2 = blk(); r2[2 + colOffset] = `CÔNG TRÌNH: ${project.client || ''}`.toUpperCase(); aoaArray.push(r2);

    // Row 3 (Excel row 4): Blank

    aoaArray.push(blk());

    // Row 4 (Excel row 5): Từ | Kính gởi

    const r4 = blk(); r4[0 + colOffset] = `Từ : ${project.sender || ''}`; r4[4 + colOffset] = `Kính gởi: ${project.recipient || ''}`; aoaArray.push(r4);

    // Row 5 (Excel row 6): Công Ty bên A | Công Ty bên B

    const r5 = blk(); r5[0 + colOffset] = `Công Ty: ${project.company || ''}`; r5[4 + colOffset] = `Công Ty: ${project.clientCo || ''}`; aoaArray.push(r5);

    // Row 6 (Excel row 7): Địa chỉ bên A | Địa chỉ bên B

    const r6 = blk(); r6[0 + colOffset] = `Địa chỉ : ${project.companyAddr || ''}`; r6[4 + colOffset] = `Địa chỉ : ${project.clientAddr || project.address || ''}`; aoaArray.push(r6);

    // Row 7 (Excel row 8): Blank

    aoaArray.push(blk());

    // Merges phần header thông tin (rows 0-6, tức Excel rows 1-7)

    // Row 0,1,2: C(2) → cuối = merge [2..maxCols-1], A(0) chỉ 1 ô

    [0,1,2].forEach(r => mergesArray.push({s:{r,c:2 + colOffset}, e:{r,c:maxCols-1}}));

    // Row 4,5,6: Từ = A(0)..C(3), Kính gởi = E(4)..cuối

    [4,5,6].forEach(r => {

      mergesArray.push({s:{r,c:0 + colOffset}, e:{r,c:3 + colOffset}});

      mergesArray.push({s:{r,c:4 + colOffset}, e:{r,c:maxCols-1}});

    });

  };

    const romanNums = ['I','II','III','IV','V','VI','VII','VIII','IX','X','XI','XII','XIII','XIV','XV','XVI','XVII','XVIII','XIX','XX'];

  // ==========================================================

  // PHASE 1: GENERATE ALL ROOM DETAIL WORKSHEETS FIRST

  // ==========================================================

  project.rooms.forEach((room, idx) => {

    const aoa = [];
    const merges = [];

    buildHeader(aoa, merges, `BẢNG KHỐI LƯỢNG - ${room.name.toUpperCase()}`, 10, 0);

    // Row 8 & 9: Table Header

    aoa.push(['STT', 'HẠNG MỤC', 'KÍCH THƯỚC', '', '', 'Đ. VỊ', 'SỐ LƯỢNG', 'ĐƠN GIÁ', 'THÀNH TIỀN', 'GHI CHÚ']);

    aoa.push(['', '', 'DÀI', 'RỘNG', 'CAO', '', '', '', '', '']);

    merges.push({s:{r:8,c:0},  e:{r:9,c:0}});  // STT

    merges.push({s:{r:8,c:1},  e:{r:9,c:1}});  // HẠNG MỤC

    merges.push({s:{r:8,c:2},  e:{r:8,c:4}});  // KÍCH THƯỚC

    merges.push({s:{r:8,c:5},  e:{r:9,c:5}});  // Đ. VỊ

    merges.push({s:{r:8,c:6},  e:{r:9,c:6}});  // SỐ LƯỢNG

    merges.push({s:{r:8,c:7},  e:{r:9,c:7}});  // ĐƠN GIÁ

    merges.push({s:{r:8,c:8},  e:{r:9,c:8}});  // THÀNH TIỀN

    merges.push({s:{r:8,c:9},  e:{r:9,c:9}});  // GHI CHÚ

    let curRow = 10;

    let itemStt = 1;

    const blkDetail = () => Array(10).fill('');

    const calc = CALC.room(room);

    let roomTotal = 0;
    let nextSectionNum = 2;
    const formulaMap = []; // {r: aoa_row, c: col, f: formula_string}
    const rowMap = {};     // key -> Excel row index (1-based)

    const renderItem = (item) => {
      if (item.surface === 'custom') {
        const ci = (room.customItems || []).find(c => c.id === item.itemId);
        if (ci) {
          const labelTrim = (ci.label || '').trim();
          const isSubHdr = labelTrim.length > 1 && labelTrim === labelTrim.toUpperCase();
          if (isSubHdr) {
            const hdr = blkDetail();
            hdr[0] = '';
            hdr[1] = ci.label;
            itemStt = 1;
            aoa.push(hdr);
            curRow++;
            return;
          }
        }
      }

      if (item.surface === 'elecHeader') {
        return;
      }

      if (item.surface === 'noteHeader') {
        const hdr = blkDetail();
        hdr[0] = '';
        hdr[1] = 'CHI TIẾT TỪ GHI CHÚ';
        itemStt = 1;
        aoa.push(hdr);
        curRow++;
        return;
      }

      const noStt = false;
      const isManual = item.surface === 'elecManual';
      const sttVal = noStt ? '' : itemStt++;

      const daiNum  = item.dai  ? +item.dai  : null;
      const rongNum = item.rong ? +item.rong : null;
      const caoNum  = item.cao  ? +item.cao  : null;

      const qtyVal = (isManual && item.qty === 0) ? null : fmtNum(item.qty, 2);
      const priceVal = (item.price !== undefined && item.price !== null && item.price !== '') ? fmtNum(item.price, 0) : null;
      const totalVal = (item.total !== undefined && item.total !== null && item.total !== '') ? fmtNum(item.total, 0) : null;
      let wasteStr = item.note || '';

      const aoaRow = curRow;

      aoa.push([
        sttVal,
        item.label,
        daiNum,
        rongNum,
        caoNum,
        item.unit,
        qtyVal,
        priceVal,
        totalVal,
        wasteStr,
      ]);

      // Record row mapping
      const itemKey = `${item.label.trim()}||${item.unit.trim()}`;
      rowMap[itemKey] = aoaRow + 1;

      roomTotal += (item.total || 0);

      // Excel formula for Quantity (column G = index 6)
      const exR = aoaRow + 1;
      let qtyFormula = null;

      if (item.surface === 'floor' && daiNum && rongNum) {
        const waste = item.qty > 0 ? +(item.qty / ((+item.dai/1000)*(+item.rong/1000))).toFixed(4) : 1;
        qtyFormula = `C${exR}/1000*D${exR}/1000*${waste.toFixed(4)}`;
      } else if (item.surface === 'ceiling' && daiNum && rongNum) {
        const waste = item.qty > 0 ? +(item.qty / ((+item.dai/1000)*(+item.rong/1000))).toFixed(4) : 1;
        qtyFormula = `C${exR}/1000*D${exR}/1000*${waste.toFixed(4)}`;
      } else if (item.surface === 'perimeter' && daiNum && rongNum) {
        qtyFormula = `(C${exR}*2+D${exR}*2)/1000`;
      } else if (item.surface === 'ceilPerim' && daiNum && rongNum) {
        qtyFormula = `(C${exR}*2+D${exR}*2)/1000`;
      } else if ((item.surface === 'wall' || item.surface === 'wallZ1' || item.surface === 'wallZ2') && daiNum && caoNum) {
        const waste = item.qty > 0 ? +(item.qty / ((+item.dai/1000)*(+item.cao/1000))).toFixed(4) : 1;
        qtyFormula = `C${exR}/1000*E${exR}/1000*${waste.toFixed(4)}`;
      } else if ((item.surface === 'door' || item.surface === 'window') && rongNum && caoNum) {
        const factor = item.qty > 0 ? +(item.qty / ((+item.rong/1000)*(+item.cao/1000))).toFixed(4) : 1;
        qtyFormula = `D${exR}/1000*E${exR}/1000*${factor.toFixed(4)}`;
      }

      if (qtyFormula) {
        formulaMap.push({ r: aoaRow, c: 6, f: qtyFormula, v: item.qty });
      }
      curRow++;
    };

    // I. XÂY DỰNG CƠ BẢN
    const secIHeader = blkDetail();
    secIHeader[0] = 'I';
    secIHeader[1] = 'XÂY DỰNG CƠ BẢN';
    aoa.push(secIHeader);
    // Merge STT → ĐƠn giá (col 0⊒7) cho dòng header nhóm
    merges.push({ s: { r: curRow, c: 0 }, e: { r: curRow, c: 7 } });
    curRow++;

    if (room.roomNote) {
      const noteR = blkDetail();
      noteR[1] = `• ${room.roomNote}`;
      aoa.push(noteR);
      merges.push({s:{r:curRow,c:1}, e:{r:curRow,c:9}});
      curRow++;
    }

    const constrItems = calc.items.filter(item => !['woodworkNote', 'plumbingNote', 'waterproofNote', 'elecHeader', 'elec', 'elecManual'].includes(item.surface));
    if (constrItems.length === 0) {
      const er = blkDetail(); er[1] = '(Chưa chọn vật liệu)';
      aoa.push(er);
      curRow++;
    } else {
      constrItems.forEach(item => {
        renderItem(item);
      });
    }

    // II. THIẾT BỊ ĐIỆN
    const elecItems = calc.items.filter(item => item.surface === 'elec' || item.surface === 'elecManual');
    if (elecItems.length > 0) {
      const secIIHeader = blkDetail();
      secIIHeader[0] = 'II';
      secIIHeader[1] = 'THIẾT BỊ ĐIỆN';
      aoa.push(secIIHeader);
      // Merge STT → ĐƠn giá (col 0⊒7) cho dòng header nhóm
      merges.push({ s: { r: curRow, c: 0 }, e: { r: curRow, c: 7 } });
      curRow++;
      itemStt = 1;
      nextSectionNum = 3;
      elecItems.forEach(item => {
        renderItem(item);
      });
    }

    // III. THIẾT BỊ NỘI THẤT
    if (room.noteWoodwork && room.noteWoodwork.trim()) {
      const secIIIHeader = blkDetail();
      secIIIHeader[0] = 'III';
      secIIIHeader[1] = 'THIẾT BỊ NỘI THẤT';
      aoa.push(secIIIHeader);
      // Merge STT → ĐƠn giá (col 0⊒7) cho dòng header nhóm
      merges.push({ s: { r: curRow, c: 0 }, e: { r: curRow, c: 7 } });
      curRow++;
      nextSectionNum = 4;

      const noteLines = room.noteWoodwork.split('\n').map(l => l.trim()).filter(l => l);
      noteLines.forEach((line, li) => {
        const parsed = parseNoteDimensionLine(line);
        const lr = blkDetail();
        lr[0] = li + 1;
        lr[1] = parsed.label;
        lr[2] = parsed.dai;
        lr[3] = parsed.rong;
        lr[4] = parsed.cao;
        lr[5] = parsed.unit;
        lr[6] = parsed.qty;
        aoa.push(lr);

        const itemKey = `${parsed.label.trim()}||${parsed.unit.trim()}`;
        rowMap[itemKey] = curRow + 1;

        if (!parsed.dai && !parsed.rong && !parsed.cao) {
          merges.push({ s: { r: curRow, c: 1 }, e: { r: curRow, c: 4 } });
        }
        curRow++;
      });
    }

    // IV. NHÀ VỆ SINH: THIẾT BỊ VỆ SINH VÀ CHỐNG THẤM
    const toiletText = [room.notePlumbing, room.noteWaterproof].filter(Boolean).join('\n');
    if (toiletText.trim()) {
      const secIVHeader = blkDetail();
      secIVHeader[0] = 'IV';
      secIVHeader[1] = 'NHÀ VỆ SINH: THIẾT BỊ VỆ SINH VÀ CHỐNG THẤM';
      aoa.push(secIVHeader);
      // Merge STT → ĐƠn giá (col 0⊒7) cho dòng header nhóm
      merges.push({ s: { r: curRow, c: 0 }, e: { r: curRow, c: 7 } });
      curRow++;
      nextSectionNum = 5;

      const noteLines = toiletText.split('\n').map(l => l.trim()).filter(l => l);
      noteLines.forEach((line, li) => {
        const parsed = parseNoteDimensionLine(line);
        const lr = blkDetail();
        lr[0] = li + 1;
        lr[1] = parsed.label;
        lr[2] = parsed.dai;
        lr[3] = parsed.rong;
        lr[4] = parsed.cao;
        lr[5] = parsed.unit;
        lr[6] = parsed.qty;
        aoa.push(lr);

        const itemKey = `${parsed.label.trim()}||${parsed.unit.trim()}`;
        rowMap[itemKey] = curRow + 1;

        if (!parsed.dai && !parsed.rong && !parsed.cao) {
          merges.push({ s: { r: curRow, c: 1 }, e: { r: curRow, c: 4 } });
        }
        curRow++;
      });
    }

    // CHI PHÍ KHÁC per room

    {

      const oc = project.otherCosts || {};

      const tf = (+room.D||0)/1000 * (+room.R||0)/1000;

      const OC_DETAIL = [

        { key:'transport',   label:'Phí vận chuyển',                                               unit:'gói', autoQty:false, defaultQty:1 },

        { key:'debris',      label:'Phí tháo gỡ trần, vận chuyển + đổ xà bần, bao đựng rác',       unit:'m²',  autoQty:true },

        { key:'scaffold',    label:'Phí thuê giàn giáo',                                             unit:'m²',  autoQty:true },

        { key:'design',      label:'Phí thiết kế',                                                   unit:'m²',  autoQty:true },

        { key:'supervision', label:'Phí giám sát ngoại tỉnh',                                        unit:'lần', autoQty:false, defaultQty:1 },

      ];

      let hasRoomOc = false;

      let roomOcStt = 1;

      OC_DETAIL.forEach(tmpl => {

        const saved = oc[tmpl.key] || {};

        const qty = tmpl.autoQty ? +tf.toFixed(2) : +(saved.qty != null ? saved.qty : tmpl.defaultQty);

        const price = +(saved.price || 0);

        const total = qty * price;

        if (price > 0 || qty > 0) {

          roomTotal += (total || 0);

          if (!hasRoomOc) {

            const hdr = blkDetail();

            hdr[0] = romanNums[nextSectionNum - 1] || nextSectionNum;

            hdr[1] = 'CHI PHÍ KHÁC';

            aoa.push(hdr);

            curRow++;

            hasRoomOc = true;

          }

          const aoaRow = curRow;

          aoa.push([

            roomOcStt++,

            tmpl.label,

            '', '', '', // dimensions blank

            tmpl.unit,

            qty,

            price ? fmtNum(price, 0) : '',

            total ? fmtNum(total, 0) : '',

            saved.note || '',

          ]);

          // Record other cost row mapping

          const itemKey = `${tmpl.label.trim()}||${tmpl.unit.trim()}`;

          rowMap[itemKey] = aoaRow + 1;

          curRow++;

        }

      });

    }

    // Subtotal, VAT, Grand total rows in room sheets

    // Cộng trước VAT

    const preVatRow = blkDetail(); preVatRow[1] = 'Cộng trước VAT';

    aoa.push(preVatRow);

    formulaMap.push({ r: curRow, c: 8, f: `SUM(I11:I${curRow})`, v: roomTotal });

    merges.push({ s: { r: curRow, c: 1 }, e: { r: curRow, c: 7 } });

    const preVatExcelRow = curRow + 1; // 1-based Excel row number

    curRow++;

    // Thuế VAT

    const vatRow = blkDetail(); vatRow[1] = `Thuế VAT (${project.vatRate ?? 8}%)`;

    aoa.push(vatRow);

    formulaMap.push({ r: curRow, c: 8, f: `ROUND(I${preVatExcelRow}*${(project.vatRate ?? 8)/100},0)`, v: Math.round(roomTotal * (project.vatRate ?? 8)/100) });

    merges.push({ s: { r: curRow, c: 1 }, e: { r: curRow, c: 7 } });

    const vatExcelRow = curRow + 1;

    curRow++;

    // TỔNG CỘNG

    const grandRow = blkDetail(); grandRow[1] = 'TỔNG CỘNG';

    aoa.push(grandRow);

    formulaMap.push({ r: curRow, c: 8, f: `I${preVatExcelRow}+I${vatExcelRow}`, v: roomTotal + Math.round(roomTotal * (project.vatRate ?? 8)/100) });

    merges.push({ s: { r: curRow, c: 1 }, e: { r: curRow, c: 7 } });

    curRow++;

    // Bằng chữ

    const vatRateRoom   = +(project.vatRate ?? 8) / 100;

    const vatAmtRoom    = Math.round(roomTotal * vatRateRoom);

    const grandTotalRoom = roomTotal + vatAmtRoom;

    const wordsRow = blkDetail(); wordsRow[1] = `Bằng chữ: ${numberToWords(grandTotalRoom)}`;

    aoa.push(wordsRow);

    merges.push({ s: { r: curRow, c: 1 }, e: { r: curRow, c: 9 } });

    curRow++;

    // Blank row

    aoa.push(blkDetail());

    curRow++;

    // Note 1

    const noteRow1 = blkDetail(); noteRow1[1] = '_ Báo giá trên có giá trị trong vòng 30 ngày';

    aoa.push(noteRow1);

    merges.push({ s: { r: curRow, c: 1 }, e: { r: curRow, c: 9 } });

    curRow++;

    // Note 2

    const noteRow2 = blkDetail(); noteRow2[1] = '_ Báo giá trên không bao gồm:';

    aoa.push(noteRow2);

    merges.push({ s: { r: curRow, c: 1 }, e: { r: curRow, c: 9 } });

    curRow++;

    // Note 3

    const noteRow3 = blkDetail(); noteRow3[1] = '_ Thời gian thi công:';

    aoa.push(noteRow3);

    merges.push({ s: { r: curRow, c: 1 }, e: { r: curRow, c: 9 } });

    curRow++;

    // Signatures blocks in room sheets

    aoa.push(blkDetail()); curRow++; // blank

    const dateRow = blkDetail();

    dateRow[6] = 'TP. HCM ngày ...... tháng ...... năm 2026';

    aoa.push(dateRow);

    merges.push({ s: { r: curRow, c: 6 }, e: { r: curRow, c: 9 } });

    curRow++;

    const sigRow = blkDetail();

    sigRow[1] = 'Xác nhận của khách hàng';

    sigRow[6] = 'Giám đốc';

    aoa.push(sigRow);

    merges.push({ s: { r: curRow, c: 1 }, e: { r: curRow, c: 5 } });

    merges.push({ s: { r: curRow, c: 6 }, e: { r: curRow, c: 9 } });

    curRow++;

    aoa.push(blkDetail()); curRow++;

    aoa.push(blkDetail()); curRow++;

    const nameRow = blkDetail();

    nameRow[6] = 'VŨ THỊ KIM CHÚC';

    aoa.push(nameRow);

    merges.push({ s: { r: curRow, c: 6 }, e: { r: curRow, c: 9 } });

    curRow++;

    const wsDetail = XLSX.utils.aoa_to_sheet(aoa);

    wsDetail.isDetail = true;

    // Apply quantity formulas

    formulaMap.forEach(({r, c, f, v}) => {

      const cellRef = XLSX.utils.encode_cell({r, c});

      wsDetail[cellRef] = { t: 'n', f };

      if (v !== undefined && v !== null) {

        wsDetail[cellRef].v = v;

        wsDetail[cellRef].w = fmt(v, c === 6 ? 2 : 0);

      }

    });

    wsDetail['!merges'] = merges;

    wsDetail['!cols'] = [

      { wch: 6  },  // STT

      { wch: 32 },  // Hạng mục

      { wch: 8  },  // Dài

      { wch: 8  },  // Rộng

      { wch: 8  },  // Cao

      { wch: 6  },  // ĐVT

      { wch: 11 },  // SL

      { wch: 12 },  // ĐG

      { wch: 13 },  // TT

      { wch: 20 },  // Ghi chú

    ];

    applyPageSetup(wsDetail, 9);

    applySheetStyles(wsDetail, 8, 'detail');

    applyBoldSectionRows(wsDetail, 7);

    // Resolve name collision

    let sheetName = room.name.replace(/[:\?\*\\\/\[\]]/g, '').trim();

    if (sheetName.length > 30) sheetName = sheetName.substring(0, 30);

    let finalSheetName = sheetName || `Phong_${idx + 1}`;

    let suffix = 1;

    while (roomSheets.some(s => s.finalSheetName === finalSheetName)) {

      finalSheetName = `${sheetName.substring(0, 25)}_${suffix++}`;

    }

    roomSheets.push({ room, ws: wsDetail, finalSheetName, rowMap, calcItems: calc.items });

  });

  // ==========================================================

  // PHASE 2: GENERATE SHEET 1 - "Tổng hợp"

  // ==========================================================

  const rooms = project.rooms || [];

  const sumCols = 7 + rooms.length; // STT + Hạng mục + ĐV + rooms... + Tổng + ĐG + TT + Ghi chú

  const aoaSum = [];

  const mergesSum = [];

  const formulaMapSum = [];

  buildHeader(aoaSum, mergesSum, 'BẢNG TỔNG HỢP KHỐI LƯỢNG', sumCols);

  // Row 8: Dynamic Table Header

  const sumHeaderRow = ['STT', 'HẠNG MỤC', 'Đ. VỊ'];

  rooms.forEach(r => sumHeaderRow.push(r.name.toUpperCase()));

  sumHeaderRow.push('TỔNG SỐ LƯỢNG', 'ĐƠN GIÁ', 'THÀNH TIỀN', 'GHI CHÚ');

  aoaSum.push(sumHeaderRow);

  const summaryItems = CALC.projectSummary(project);

  const groups = { construction: [], furniture: [], elec: [], sanitary: [] };

  summaryItems.forEach(item => {

    groups[categorizeSummaryItem(item)].push(item);

  });

  const catRomNums = ['I', 'II', 'III', 'IV', 'V', 'VI'];

  let catRomIdx = 0;

  let curRowSum = 9;

  let grandTotalSum = 0;

  const categoriesConfig = [
    { key: 'construction', rom: 'I',   label: 'XÂY DỰNG CƠ BẢN (bao gồm tất cả các hạng mục sàn tường trần)' },
    { key: 'elec',         rom: 'II',  label: 'THIẾT BỊ ĐIỆN' },
    { key: 'furniture',    rom: 'III', label: 'THIẾT BỊ NỘI THẤT' },
    { key: 'sanitary',     rom: 'IV',  label: 'NHÀ VỆ SINH: THIẾT BỊ VỆ SINH VÀ CHỐNG THẤM' }
  ];

  categoriesConfig.forEach(catConf => {

    const itemsInCat = groups[catConf.key];

    if (itemsInCat && itemsInCat.length > 0) {

      const catHdr = Array(sumCols).fill('');

      catHdr[0] = catConf.rom;

      catHdr[1] = catConf.label.toUpperCase();

      aoaSum.push(catHdr);

      // Merge STT → ĐƠn giá (col 0 → sumCols-3) cho dòng header nhóm
      mergesSum.push({ s: { r: curRowSum, c: 0 }, e: { r: curRowSum, c: sumCols - 3 } });

      curRowSum++;

      let itemStt = 1;

      itemsInCat.forEach(item => {

        const exRSum = curRowSum + 1;

        const row = [itemStt++, item.label, item.unit];

        // Room quantity formulas

        rooms.forEach((r, rIdx) => {

          const rSheet = roomSheets[rIdx];

          const itemKey = `${item.label.trim()}||${item.unit.trim()}`;

          const itemRowInRoom = rSheet.rowMap[itemKey];

          if (itemRowInRoom) {

            const roomItem = rSheet.calcItems.find(ci => ci.label.trim() === item.label.trim() && ci.unit.trim() === item.unit.trim());
            const qtyVal = roomItem ? roomItem.qty : 0;

            row.push(null);

            formulaMapSum.push({

              r: curRowSum,

              c: 3 + rIdx,

              f: `'${rSheet.finalSheetName}'!G${itemRowInRoom}`,

              v: qtyVal

            });

          } else {

            row.push(null);

          }

        });

        // TỔNG SỐ LƯỢNG formula (SUM across room columns)

        const firstRoomCol = XLSX.utils.encode_col(3);

        const lastRoomCol = XLSX.utils.encode_col(2 + rooms.length);

        const totalQtyCol = XLSX.utils.encode_col(3 + rooms.length);

        const priceCol = XLSX.utils.encode_col(4 + rooms.length);

        const totalAmtCol = XLSX.utils.encode_col(5 + rooms.length);

        row.push(null);

        formulaMapSum.push({

          r: curRowSum,

          c: 3 + rooms.length,

          f: `SUM(${firstRoomCol}${exRSum}:${lastRoomCol}${exRSum})`,

          v: item.qty

        });

        // ĐƠN GIÁ (static)

        row.push((item.price !== undefined && item.price !== null && item.price !== '') ? fmtNum(item.price, 0) : null);

        // THÀNH TIỀN formula

        row.push(null);

        formulaMapSum.push({

          r: curRowSum,

          c: 5 + rooms.length,

          f: `${totalQtyCol}${exRSum}*${priceCol}${exRSum}`,

          v: item.total

        });

        row.push(item.note || '');

        aoaSum.push(row);

        grandTotalSum += item.total || 0;

        curRowSum++;

      });

    }

  });

  // CHI PHÍ KHÁC (Sheet Tổng Hợp)

  let ocStt = 1;

  const oc = project.otherCosts || {};

  const totalFloor = rooms.reduce((s, r) => s + (+r.D||0)/1000 * (+r.R||0)/1000, 0);

  const OC_TEMPLATE = [

    { key: 'transport',   label: 'Phí vận chuyển',   unit: 'gói',   autoQty: false, defaultQty: 1 },

    { key: 'debris',      label: 'Phí tháo gỡ trần, vận chuyển + đổ xà bần, bao đựng rác',       unit: 'm²',       autoQty: true },

    { key: 'scaffold',    label: 'Phí thuê giàn giáo',                                             unit: 'm²',       autoQty: true },

    { key: 'design',      label: 'Phí thiết kế',                                                   unit: 'm²',       autoQty: true },

    { key: 'supervision', label: 'Phí giám sát ngoại tỉnh',                                        unit: 'lần',      autoQty: false, defaultQty: 1 },

  ];

  let hasOcSum = false;

  OC_TEMPLATE.forEach(tmpl => {

    const saved = oc[tmpl.key] || {};

    const qty = tmpl.autoQty ? +(totalFloor).toFixed(2) : +(saved.qty != null ? saved.qty : tmpl.defaultQty);

    const price = +(saved.price || 0);

    const total = qty * price;

    if (price > 0 || qty > 0) {

      if (!hasOcSum) {

        const ocHdr = Array(sumCols).fill('');

        ocHdr[0] = catRomNums[catRomIdx++];

        ocHdr[1] = 'CHI PHÍ KHÁC';

        aoaSum.push(ocHdr);

        // Merge STT → ĐƠn giá (col 0 → sumCols-3) cho dòng header CHI PHÍ KHÁC
        mergesSum.push({ s: { r: curRowSum, c: 0 }, e: { r: curRowSum, c: sumCols - 3 } });

        curRowSum++;

        hasOcSum = true;

      }

      const exRSum = curRowSum + 1;

      const row = [ocStt++, tmpl.label, tmpl.unit];

      rooms.forEach((r, rIdx) => {

        const rSheet = roomSheets[rIdx];

        const itemKey = `${tmpl.label.trim()}||${tmpl.unit.trim()}`;

        const itemRowInRoom = rSheet.rowMap[itemKey];

        if (itemRowInRoom) {

          const tf = (+rSheet.room.D || 0) / 1000 * (+rSheet.room.R || 0) / 1000;
          const roomQty = tmpl.autoQty ? +(tf.toFixed(2)) : +(saved.qty != null ? saved.qty : tmpl.defaultQty);

          row.push(null);

          formulaMapSum.push({

            r: curRowSum,

            c: 3 + rIdx,

            f: `'${rSheet.finalSheetName}'!G${itemRowInRoom}`,

            v: roomQty

          });

        } else {

          row.push('');

        }

      });

      row.push(null);

      const totalFormula = `SUM(${XLSX.utils.encode_col(3)}${exRSum}:${XLSX.utils.encode_col(3 + rooms.length - 1)}${exRSum})`;

      formulaMapSum.push({

        r: curRowSum,

        c: 3 + rooms.length,

        f: totalFormula,

        v: qty

      });

      row.push(price);

      row.push('');

      const totalQtyCol = XLSX.utils.encode_col(3 + rooms.length);

      const priceCol = XLSX.utils.encode_col(4 + rooms.length);

      formulaMapSum.push({

        r: curRowSum,

        c: 5 + rooms.length,

        f: `${totalQtyCol}${exRSum}*${priceCol}${exRSum}`,

        v: total

      });

      row.push(saved.note || '');

      aoaSum.push(row);

      grandTotalSum += total;

      curRowSum++;

    }

  });

  const vatRateExcel = +(project.vatRate ?? 8) / 100;

  const vatAmtExcel  = Math.round(grandTotalSum * vatRateExcel);

  const grandWithVat = grandTotalSum + vatAmtExcel;

  const totalAmtCol = XLSX.utils.encode_col(5 + rooms.length);

  // Subtotal (Cộng trước VAT)

  const subRowSum = Array(sumCols).fill(''); subRowSum[1] = 'Cộng trước VAT';

  aoaSum.push(subRowSum);

  const subRowExR = curRowSum + 1;

  formulaMapSum.push({

    r: curRowSum,

    c: 5 + rooms.length,

    f: `SUM(${totalAmtCol}11:${totalAmtCol}${curRowSum})`,

    v: grandTotalSum

  });

  mergesSum.push({s:{r:curRowSum,c:1}, e:{r:curRowSum,c:sumCols - 3}});

  curRowSum++;

  // VAT

  const vatRowSum = Array(sumCols).fill(''); vatRowSum[1] = `Thuế VAT (${Math.round(vatRateExcel * 100)}%)`;

  aoaSum.push(vatRowSum);

  const vatRowExR = curRowSum + 1;

  formulaMapSum.push({

    r: curRowSum,

    c: 5 + rooms.length,

    f: `ROUND(${totalAmtCol}${subRowExR}*${vatRateExcel},0)`,

    v: vatAmtExcel

  });

  mergesSum.push({s:{r:curRowSum,c:1}, e:{r:curRowSum,c:sumCols - 3}});

  curRowSum++;

  // TỔNG CỘNG

  const thRowSum = Array(sumCols).fill(''); thRowSum[1] = 'TỔNG CỘNG';

  aoaSum.push(thRowSum);

  const totalRowExR = curRowSum + 1;

  formulaMapSum.push({

    r: curRowSum,

    c: 5 + rooms.length,

    f: `${totalAmtCol}${subRowExR}+${totalAmtCol}${vatRowExR}`,

    v: grandWithVat

  });

  mergesSum.push({s:{r:curRowSum,c:1}, e:{r:curRowSum,c:sumCols - 3}});

  curRowSum++;

  // Bằng chữ

  const wordsRow = Array(sumCols).fill('');

  wordsRow[1] = `Bằng chữ: ${numberToWords(grandWithVat)}`;

  aoaSum.push(wordsRow);

  mergesSum.push({s:{r:curRowSum,c:1}, e:{r:curRowSum,c:sumCols - 1}});

  curRowSum++;

  // Footer notes in Tổng hợp

  const noteRow1 = Array(sumCols).fill('');

  noteRow1[1] = '_ Báo giá trên có giá trị trong vòng 30 ngày';

  aoaSum.push(noteRow1);

  mergesSum.push({ s: { r: curRowSum, c: 1 }, e: { r: curRowSum, c: sumCols - 1 } });

  curRowSum++;

  const noteRow2 = Array(sumCols).fill('');

  noteRow2[1] = '_ Báo giá trên không bao gồm:';

  aoaSum.push(noteRow2);

  mergesSum.push({ s: { r: curRowSum, c: 1 }, e: { r: curRowSum, c: sumCols - 1 } });

  curRowSum++;

  const noteRow3 = Array(sumCols).fill('');

  noteRow3[1] = '_ Thời gian thi công:';

  aoaSum.push(noteRow3);

  mergesSum.push({ s: { r: curRowSum, c: 1 }, e: { r: curRowSum, c: sumCols - 1 } });

  curRowSum++;

  aoaSum.push(Array(sumCols).fill('')); curRowSum++; // blank

  const dateRowSum = Array(sumCols).fill('');

  dateRowSum[rooms.length + 3] = 'TP. HCM ngày ...... tháng ...... năm 2026';

  aoaSum.push(dateRowSum);

  mergesSum.push({ s: { r: curRowSum, c: rooms.length + 3 }, e: { r: curRowSum, c: sumCols - 1 } });

  curRowSum++;

  const sigRowSum = Array(sumCols).fill('');

  sigRowSum[1] = 'Xác nhận của khách hàng';

  sigRowSum[rooms.length + 3] = 'Giám đốc';

  aoaSum.push(sigRowSum);

  mergesSum.push({ s: { r: curRowSum, c: 1 }, e: { r: curRowSum, c: rooms.length + 2 } });

  mergesSum.push({ s: { r: curRowSum, c: rooms.length + 3 }, e: { r: curRowSum, c: sumCols - 1 } });

  curRowSum++;

  aoaSum.push(Array(sumCols).fill('')); curRowSum++;

  aoaSum.push(Array(sumCols).fill('')); curRowSum++;

  const nameRowSum = Array(sumCols).fill('');

  nameRowSum[rooms.length + 3] = 'VŨ THỊ KIM CHÚC';

  aoaSum.push(nameRowSum);

  mergesSum.push({ s: { r: curRowSum, c: rooms.length + 3 }, e: { r: curRowSum, c: sumCols - 1 } });

  curRowSum++;

  const wsSum = XLSX.utils.aoa_to_sheet(aoaSum);

  wsSum['!merges'] = mergesSum;

  // Apply formulas to wsSum

  formulaMapSum.forEach(({r, c, f, v}) => {

    const cellRef = XLSX.utils.encode_cell({r, c});

    wsSum[cellRef] = { t: 'n', f };

    if (v !== undefined && v !== null) {

      wsSum[cellRef].v = v;

      wsSum[cellRef].w = fmt(v, (c >= 3 && c <= 3 + rooms.length) ? 2 : 0);

    }

  });

  // Column widths for Tổng hợp

  const sumColWidths = [{ wch: 6.33 }, { wch: 35.0 }, { wch: 6 }];

  rooms.forEach(() => sumColWidths.push({ wch: 10 }));

  sumColWidths.push({ wch: 11 }, { wch: 12 }, { wch: 13 }, { wch: 24 });

  wsSum['!cols'] = sumColWidths;

  applyPageSetup(wsSum, 9);

  applySheetStyles(wsSum, 8, 'sum');

  applyBoldSectionRows(wsSum, 7);

  // Append Tổng hợp and Room sheets to wb

  XLSX.utils.book_append_sheet(wb, wsSum, "Tổng hợp");

  roomSheets.forEach(s => {

    XLSX.utils.book_append_sheet(wb, s.ws, s.finalSheetName);

  });

  // ==========================================================

  // PHASE 3: GENERATE SHEET "Vật Tư Cần Mua" (wsVT)

  // ==========================================================

  let wsVT;

  (() => {

    const matMap = new Map();

    const GROUP_LABEL = {

      floor:      'SÀN',

      wall:       'TƯỜNG SƠN NƯỚC',

      ceiling:    'TRẦN SƠN NƯỚC',

      perimeter:  'CHU VI / ĐỊA ĐẲNG',

      ceilPerim:  'CHU VI TRẦN',

      window:     'CỬA',

      ceilMat:    'ỐP TRẦN VẬT LIỆU',

      floorMat:   'ỐP SÀN VẬT LIỆU',

      wallMat:    'ỐP TƯỜNG VẬT LIỆU',

      elec:       'THIẾT BỊ ĐIỆN',

      elecManual: 'THIẾT BỊ ĐIỆN',

      noteItem:   'VẬT TƯ KHÁC',

    };

    rooms.forEach(room => {

      const calc = CALC.room(room);

      calc.items.forEach(item => {

        if (['elecHeader','noteHeader','perimeter','ceilPerim'].includes(item.surface)) return;

        if (!item.qty || item.qty <= 0) return;

        const key = `${item.surface}||${item.label}||${item.unit}`;

        if (!matMap.has(key)) {

          matMap.set(key, {

            surface:  item.surface,

            group:    GROUP_LABEL[item.surface] || 'KHÁC',

            label:    item.label,

            unit:     item.unit,

            price:    item.price || 0,

            note:     item.note  || '',

            rooms:    [],

            totalQty: 0,

            totalAmt: 0,

          });

        }

        const m = matMap.get(key);

        m.totalQty += item.qty || 0;

        m.totalAmt += item.total || 0;

        m.rooms.push(room.name);

        if (item.price) m.price = item.price;

      });

    });

    const surfaceOrder = ['floor','wall','ceiling','ceilMat','floorMat','wallMat','window','elec','elecManual','noteItem'];

    const matList = [...matMap.values()].sort((a,b) => {

      const ga = surfaceOrder.indexOf(a.surface);

      const gb = surfaceOrder.indexOf(b.surface);

      if (ga !== gb) return ga - gb;

      return a.label.localeCompare(b.label);

    });

    const VT_COLS = 10;

    const aoaVT  = [];

    const mergesVT = [];

    const formulaMapVT = [];

    buildHeader(aoaVT, mergesVT, 'DANH SÁCH VẬT TƯ CẦN MUA', VT_COLS);

    aoaVT.push(['STT', 'TÊN VẬT TƯ / HẠNG MỤC', 'ĐVT', 'KL TÍNH TOÁN', 'KL CẦN MUA (+ 5% DP)', 'ĐƠN GIÁ', 'THÀNH TIỀN (DT)', 'PHÒNG SỬ DỤNG', 'NHÀ CUNG CẤP', 'GHI CHÚ']);

    let curRowVT = aoaVT.length - 1;

    curRowVT++;

    let stt = 1;

    let prevGroup = null;

    let groupStartRow = curRowVT;

    let groupTotalRows = [];

    let vtGrandTotal = 0;

    let groupTotalVal = 0;

    const pushGroupTotal = (group) => {

      if (prevGroup === null) return;

      const gRow = Array(VT_COLS).fill('');

      gRow[0] = `CỘNG ${prevGroup}`;

      const sumRange = `G${groupStartRow + 1}:G${curRowVT}`;

      gRow[6] = ''; // placeholder for group total

      formulaMapVT.push({ r: curRowVT, c: 6, f: `SUM(${sumRange})`, v: groupTotalVal });

      groupTotalVal = 0;

      groupTotalRows.push(curRowVT + 1); // 1-based row index

      aoaVT.push(gRow);

      mergesVT.push({s:{r:curRowVT,c:0}, e:{r:curRowVT,c:5}});

      curRowVT++;

    };

    const vtRomNums = ['I','II','III','IV','V','VI','VII','VIII','IX','X','XI','XII','XIII','XIV','XV','XVI','XVII','XVIII','XIX','XX'];

    let vtRomIdx = 0;

    matList.forEach(m => {

      if (m.group !== prevGroup) {

        pushGroupTotal(prevGroup);

        const gHdr = Array(VT_COLS).fill('');

        gHdr[0] = vtRomNums[vtRomIdx++] || '';

        gHdr[1] = m.group;

        aoaVT.push(gHdr);

        curRowVT++;

        prevGroup = m.group;

        groupStartRow = curRowVT;

        stt = 1; // reset STT for group

      }

      const exRVT = curRowVT + 1;

      const matchingCells = [];

      // Link calculated quantity to individual room detail sheet cells

      rooms.forEach((room, rIdx) => {

        const rSheet = roomSheets[rIdx];

        const itemKey = `${m.label.trim()}||${m.unit.trim()}`;

        const itemRowInRoom = rSheet.rowMap[itemKey];

        if (itemRowInRoom) {

          matchingCells.push(`'${rSheet.finalSheetName}'!G${itemRowInRoom}`);

        }

      });

      const qtyFormula = matchingCells.length > 0 ? matchingCells.join('+') : '0';

      aoaVT.push([

        stt++,

        m.label,

        m.unit,

        null, // KL tính toán formula

        null, // KL cần mua formula

        (m.price !== undefined && m.price !== null && m.price !== '') ? fmtNum(m.price, 0) : null,

        null, // Thành tiền formula

        [...new Set(m.rooms)].join(', '),

        null, // NCC

        m.note || '',

      ]);

      formulaMapVT.push({ r: curRowVT, c: 3, f: qtyFormula, v: m.qty });

      formulaMapVT.push({ r: curRowVT, c: 4, f: `D${exRVT}*1.05`, v: m.qty * 1.05 });

      formulaMapVT.push({ r: curRowVT, c: 6, f: `E${exRVT}*F${exRVT}`, v: m.total });

      groupTotalVal += (m.total || 0);

      vtGrandTotal += (m.total || 0);

      curRowVT++;

    });

    pushGroupTotal(prevGroup);

    aoaVT.push(Array(VT_COLS).fill('')); curRowVT++; // blank

    // TỔNG CỘNG VẬT TƯ

    const sumRow = Array(VT_COLS).fill('');

    sumRow[0] = 'TỔNG CỘNG VẬT TƯ (THEO DỰ TOÁN)';

    sumRow[6] = '';

    const grandFormula = groupTotalRows.length > 0 ? groupTotalRows.map(r => `G${r}`).join('+') : '0';

    formulaMapVT.push({ r: curRowVT, c: 6, f: grandFormula });

    aoaVT.push(sumRow);

    mergesVT.push({s:{r:curRowVT,c:0}, e:{r:curRowVT,c:5}});

    curRowVT++;

    // Ghi chú cuối

    const noteVT1 = Array(VT_COLS).fill('');

    noteVT1[0] = '* Cột "KL Cần Mua" đã cộng thêm 5% dự phòng hao hụt vận chuyển';

    aoaVT.push(noteVT1); mergesVT.push({s:{r:curRowVT,c:0}, e:{r:curRowVT,c:VT_COLS-1}}); curRowVT++;

    const noteVT2 = Array(VT_COLS).fill('');

    noteVT2[0] = '* Cột "Nhà Cung Cấp" để trống cho nhân viên điền khi đặt hàng';

    aoaVT.push(noteVT2); mergesVT.push({s:{r:curRowVT,c:0}, e:{r:curRowVT,c:VT_COLS-1}}); curRowVT++;

    const noteVT3 = Array(VT_COLS).fill('');

    noteVT3[0] = `* Ngày lập: ${project.date ? new Date(project.date).toLocaleDateString('vi-VN') : new Date().toLocaleDateString('vi-VN')}`;

    aoaVT.push(noteVT3); mergesVT.push({s:{r:curRowVT,c:0}, e:{r:curRowVT,c:VT_COLS-1}}); curRowVT++;

    aoaVT.push(Array(VT_COLS).fill('')); curRowVT++; // blank

    const dateRowVT = Array(VT_COLS).fill('');

    dateRowVT[6] = 'TP. HCM ngày ...... tháng ...... năm 2026';

    aoaVT.push(dateRowVT);

    mergesVT.push({ s: { r: curRowVT, c: 6 }, e: { r: curRowVT, c: 9 } });

    curRowVT++;

    const sigRowVT = Array(VT_COLS).fill('');

    sigRowVT[1] = 'Người lập bảng';

    sigRowVT[6] = 'Giám đốc';

    aoaVT.push(sigRowVT);

    mergesVT.push({ s: { r: curRowVT, c: 1 }, e: { r: curRowVT, c: 5 } });

    mergesVT.push({ s: { r: curRowVT, c: 6 }, e: { r: curRowVT, c: 9 } });

    curRowVT++;

    aoaVT.push(Array(VT_COLS).fill('')); curRowVT++;

    aoaVT.push(Array(VT_COLS).fill('')); curRowVT++;

    const nameRowVT = Array(VT_COLS).fill('');

    nameRowVT[6] = 'VŨ THỊ KIM CHÚC';

    aoaVT.push(nameRowVT);

    mergesVT.push({ s: { r: curRowVT, c: 6 }, e: { r: curRowVT, c: 9 } });

    curRowVT++;

    wsVT = XLSX.utils.aoa_to_sheet(aoaVT);

    wsVT['!merges'] = mergesVT;

    // Apply formulas to wsVT

    formulaMapVT.forEach(({r, c, f}) => {

      const cellRef = XLSX.utils.encode_cell({r, c});

      wsVT[cellRef] = { t: 'n', f };

    });

    wsVT['!cols'] = [

      { wch: 6  },  // STT

      { wch: 32 },  // Tên vật tư

      { wch: 6  },  // ĐVT

      { wch: 11 },  // KL tính toán

      { wch: 13 },  // KL cần mua (+5%)

      { wch: 12 },  // Đơn giá

      { wch: 13 },  // Thành tiền

      { wch: 20 },  // Phòng

      { wch: 15 },  // NCC

      { wch: 20 },  // Ghi chú

    ];

    applyPageSetup(wsVT, 9);

    applySheetStyles(wsVT, 8, 'vt');

    applyBoldSectionRows(wsVT, 7);

    XLSX.utils.book_append_sheet(wb, wsVT, "Vật Tư Cần Mua");

  })();

  // Setup Print Titles

  wb.Workbook = wb.Workbook || {};

  wb.Workbook.Names = wb.Workbook.Names || [];

  wb.Workbook.Names.push({

    Name: '_xlnm.Print_Titles',

    Ref: "'Tổng hợp'!$9:$9",

    Sheet: 0

  });

  roomSheets.forEach((s, sIdx) => {

    wb.Workbook.Names.push({

      Name: '_xlnm.Print_Titles',

      Ref: `'${s.finalSheetName}'!$9:$10`,

      Sheet: 1 + sIdx

    });

  });

  if (wsVT) {

    wb.Workbook.Names.push({

      Name: '_xlnm.Print_Titles',

      Ref: "'Vật Tư Cần Mua'!$9:$9",

      Sheet: 1 + roomSheets.length

    });

  }

  return { wb, wsSum, roomSheets, wsVT };

}

export function exportExcel() {
  try {
    if (typeof XLSX === 'undefined') {
      throw new Error('Thư viện SheetJS (XLSX) chưa được tải thành công. Vui lòng kiểm tra kết nối mạng!');
    }

    const project = DB.get(state.currentProjectId);
    if (!project) {
      throw new Error('Không tìm thấy dự án hiện tại!');
    }

    const wbData = generateWorkbook(project);
    if (!wbData) return;

    const dateStr = new Date().toLocaleDateString('vi-VN').replace(/\//g, '-');
    const safeProjName = (project.name || 'Du_Toan').trim().replace(/[^a-zA-Z0-9À-ỹ]+/g, '_');
    const fileName = `${safeProjName}_KhoiLuong_${dateStr}.xlsx`;

    // Xuất trực tiếp bằng SheetJS
    xlsxWriteSheetJS(wbData.wb, fileName);

    // Increment export count in localStorage
    const currentCount = parseInt(localStorage.getItem('bkl_export_count') || '0');
    try {
      localStorage.setItem('bkl_export_count', (currentCount + 1).toString());
    } catch (e) {}
    if (typeof updateDashboardStats === 'function') updateDashboardStats();
  } catch (err) {
    console.error('Lỗi khi xuất khối lượng Excel:', err);
    alert('❌ Lỗi khi xuất khối lượng Excel: ' + err.message);
  }
}

export async function exportPhotosExcel() {
  const btn = document.querySelector('.bottom-nav .nav-tab[data-tab="export"]');
  try {
    if (typeof ExcelJS === 'undefined') {
      throw new Error('Thư viện ExcelJS chưa được tải thành công. Vui lòng kiểm tra kết nối mạng!');
    }

    const project = DB.get(state.currentProjectId);
    if (!project) {
      throw new Error('Không tìm thấy dự án hiện tại!');
    }

    if (btn) {
      btn.disabled = true;
      btn.innerHTML = `<i data-lucide="loader" class="spin"></i> <span>Đang chuẩn bị...</span>`;
      if (window.lucide) window.lucide.createIcons();
    }

    const dateStr = new Date().toLocaleDateString('vi-VN').replace(/\//g, '-');
    const safeProjName = (project.name || 'Du_Toan').trim().replace(/[^a-zA-Z0-9À-ỹ]+/g, '_');
    const fileName = `${safeProjName}_AnhHienTrang_${dateStr}.xlsx`;

    await xlsxWritePhotos(project, fileName);

  } catch (err) {
    console.error('Lỗi khi xuất ảnh hiện trạng:', err);
    alert('❌ Lỗi khi xuất ảnh hiện trạng: ' + err.message);
  } finally {
    if (btn) {
      btn.disabled = false;
      btn.innerHTML = `<i data-lucide="download"></i> <span>Xuất file</span>`;
      if (window.lucide) window.lucide.createIcons();
    }
  }
}


