export async function triggerAutoSync() {
  try {
    const project = DB.get(state.currentProjectId);
    if (!project || !project.rooms || project.rooms.length === 0) return;

    const wbData = generateWorkbook(project);
    if (!wbData) return;

    const out = XLSX.write(wbData.wb, { bookType: 'xlsx', bookSST: false, type: 'binary' });
    const buf = s2ab(out);

    if (typeof JSZip === 'undefined') {
      console.warn('JSZip not found, cannot auto-sync.');
      return;
    }

    const logoBuf = logoArrayBuffer || null;
    const zip = await JSZip.loadAsync(buf);

    const sheetFiles = Object.keys(zip.files).filter(name => name.startsWith("xl/worksheets/sheet") && name.endsWith(".xml"));

    for (const file of sheetFiles) {
      let xmlStr = await zip.file(file).async("string");

      if (xmlStr.includes("<pageMargins") && !xmlStr.includes("<headerFooter")) {
        const pageSetupXml = '<pageSetup paperSize="9" orientation="landscape" fitToWidth="1" fitToHeight="0" fitToPage="1"/>';
        const footerText = '&amp;L&amp;&quot;Arial,Italic&quot;Du-Toan-BlueAI Lab&amp;R&amp;&quot;Arial,Bold&quot;Trang &amp;P/&amp;N';
        const headerFooterXml = `<headerFooter oddFooter="${footerText}" evenFooter="${footerText}"/>`;
        xmlStr = xmlStr.replace(/(<pageMargins[^>]*\/>)/, `$1${pageSetupXml}${headerFooterXml}`);
      }

      if (logoBuf && !xmlStr.includes("<drawing")) {
        xmlStr = xmlStr.replace("</worksheet>", '<drawing r:id="rId2"/></worksheet>');
        const match = file.match(/sheet(\d+)\.xml/);
        if (match) {
          const sheetNum = match[1];
          const relsFile = `xl/worksheets/_rels/sheet${sheetNum}.xml.rels`;
          const sheetRelsXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">\n<Relationship Id="rId2" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/drawing" Target="../drawings/drawing1.xml"/>\n</Relationships>`;
          zip.file(relsFile, sheetRelsXml);
        }
      }

      zip.file(file, xmlStr);
    }

    if (logoBuf) {
      const drawingXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<xdr:wsDr xmlns:xdr="http://schemas.openxmlformats.org/drawingml/2006/spreadsheetDrawing" xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main">\n<xdr:twoCellAnchor editAs="oneCell">\n<xdr:from>\n<xdr:col>1</xdr:col>\n<xdr:colOff>500000</xdr:colOff>\n<xdr:row>0</xdr:row>\n<xdr:rowOff>63501</xdr:rowOff>\n</xdr:from>\n<xdr:to>\n<xdr:col>1</xdr:col>\n<xdr:colOff>1976156</xdr:colOff>\n<xdr:row>3</xdr:row>\n<xdr:rowOff>100000</xdr:rowOff>\n</xdr:to>\n<xdr:pic>\n<xdr:nvPicPr>\n<xdr:cNvPr id="2" name="Picture 3"/>\n<xdr:cNvPicPr>\n<a:picLocks noChangeAspect="1" noChangeArrowheads="1"/>\n</xdr:picLocks>\n</xdr:picPr>\n<xdr:blipFill>\n<a:blip xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" r:embed="rId1" cstate="print"/>\n<a:srcRect/>\n<a:stretch>\n<a:fillRect/>\n</a:stretch>\n</xdr:blipFill>\n<xdr:spPr bwMode="auto">\n<a:xfrm>\n<a:off x="698500" y="63501"/>\n<a:ext cx="1476156" cy="844549"/>\n</a:xfrm>\n<a:prstGeom prst="rect">\n<a:avLst/>\n</a:prstGeom>
<a:noFill/>\n<a:ln>\n<a:noFill/>\n</a:ln>\n</xdr:spPr>\n</xdr:pic>\n<xdr:clientData/>\n</xdr:twoCellAnchor>\n</xdr:wsDr>`;
      const drawingRelsXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">\n<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/image" Target="../media/image1.png"/>\n</Relationships>`;
      
      zip.file("xl/drawings/drawing1.xml", drawingXml);
      zip.file("xl/drawings/_rels/drawing1.xml.rels", drawingRelsXml);
      zip.file("xl/media/image1.png", logoBuf);

      let contentTypes = await zip.file("[Content_Types].xml").async("string");
      if (!contentTypes.includes("/xl/drawings/drawing1.xml")) {
        contentTypes = contentTypes.replace("</Types>", '<Override PartName="/xl/drawings/drawing1.xml" ContentType="application/vnd.openxmlformats-officedocument.drawing+xml"/></Types>');
        zip.file("[Content_Types].xml", contentTypes);
      }
    }

    const zipBase64 = await zip.generateAsync({ type: "base64" });

    let folder = 'du-toan';
    const pathParts = window.location.pathname.split('/');
    for (let part of pathParts) {
      if (part.includes('du-toan') || part.includes('khoi-luong-pro')) {
        folder = decodeURIComponent(part);
        break;
      }
    }

    const response = await fetch('/api/sync-project-files', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        folder: folder,
        project_name: project.name,
        excel_base64: zipBase64
      })
    });
    
    const result = await response.json();
    console.log('Auto-sync status:', result);
  } catch (err) {
    console.error('Auto-sync error:', err);
  }
}



